package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.service.SchaalVerhogingService;
import be.schaubroeck.lpb.tools.service.SchaalVersieService;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.Builder;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;

@AllArgsConstructor
@Builder
public class FlexiJobs {

    private final AardKodeExtensieFacade aardKodeExtensieFacade;
    private final ConstantManager constantManager;
    private final LoonElementVerwerker loonElementVerwerker;
    private final SchaalVerhogingService schaalVerhogingService;
    private final SchaalVersieService schaalVersieService;
    private final FlexiJobsUtil flexiJobsUtil;

    private static final int FLEXI_LOON_AARD = 3;
    private static final int FLEXI_LOON_CODE = 22;
    private static final Set<Integer> FLEXI_LOON_EXTENSIES = ImmutableSet.of(1, 3, 21);
    private static final int FLEXI_LOON_VAKANTIEGELD_EXTENSIE = 2;

    public void vormVakantieGeld(RekenContext context, Opdracht opdracht) {
        RekenTijd rekenTijd = context.getRekenTijd();
        if (!flexiJobsUtil.isFlexiJob(opdracht, rekenTijd)) {
            return;
        }
        LoonElementManager manager = context.getLoonElementManager();
        MoneyMap<Opper> basisMap = vormBasisMap(opdracht, manager);
        Money basisTotaal = basisMap.values().stream().reduce(Money.ZERO, Money::add);
        if (basisTotaal.signum() != 0) {
            BigDecimal percentage = constantManager.getByCodeDatum(Konstanten.PCT_EVAK_VARLN, rekenTijd.eindDatum).getProcentFactor();
            Money vakantieGeld = basisTotaal.multiply(percentage).round(2);
            createLoonElementen(opdracht, basisMap, basisTotaal, vakantieGeld, manager, rekenTijd);

        }
    }

    private void createLoonElementen(
            Opdracht opdracht, MoneyMap<Opper> basisMap, Money basisTotaal, Money vakantieGeld, LoonElementManager manager, RekenTijd rekenTijd) {
        AardKodeExtensie loonCodeVakantieGeld = getLoonCodeVakantieGeld();
        MoneyMap<AardKodeExtensie> carryoverMap = new HashMoneyMap<>();
        for (Opper opper : opdracht.getOpperSlices()) {
            Money basis = basisMap.getMoney(opper);
            Money bedrag = vakantieGeld.multiply(basis.divide(basisTotaal));
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, loonCodeVakantieGeld, bedrag, rekenTijd, carryoverMap);
        }
    }

    private MoneyMap<Opper> vormBasisMap(Opdracht opdracht, LoonElementManager manager) {
        MoneyMap<Opper> basisMap = new HashMoneyMap<>();
        for (Opper opper : opdracht.getOpperSlices()) {
            Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
            Money basis = loonElementen.stream().filter(this::isFlexiLoon).map(x -> x.getPropertyMoney(RekenBrutoKey.BRUTO_MAANDLOON_KEY)).reduce(Money.ZERO, Money::add);
            basisMap.put(opper, basis);
        }
        return basisMap;
    }

    private boolean isFlexiLoon(LoonElement element) {
        AardKodeExtensie loonCode = element.getAardKodeExtensie();
        return loonCode.getAard() == FLEXI_LOON_AARD && loonCode.getCode() == FLEXI_LOON_CODE && FLEXI_LOON_EXTENSIES.contains(loonCode.getExtensie());
    }

    private AardKodeExtensie getLoonCodeVakantieGeld() {
        return aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(AkeTijdperk.DMFAPPL, AardKodeExt.V_KODE_EXT, FLEXI_LOON_CODE, FLEXI_LOON_VAKANTIEGELD_EXTENSIE);
    }

    public void doeControles(RekenContext context, Opdracht opdracht) {
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        PersoonsDataManager dataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        RekenTijd rekenTijd = context.getRekenTijd();

        FlexiJobsControleNaceCode controleNace = FlexiJobsControleNaceCode.builder().regulManager(regulManager).flexiJobsUtil(flexiJobsUtil).build();
        controleNace.check(opdracht, rekenTijd);

        BerekenWeddeSchaal berekenWeddeSchaal = BerekenWeddeSchaal.builder()
                .schaalVerhogingService(schaalVerhogingService)
                .schaalVersieService(schaalVersieService)
                .build();

        FlexiJobsControleOndergrens controleOndergrens = FlexiJobsControleOndergrens.builder()
                .constantManager(constantManager)
                .dataManager(dataManager)
                .regulManager(regulManager)
                .berekenWeddeSchaal(berekenWeddeSchaal)
                .flexiJobsUtil(flexiJobsUtil)
                .build();
        controleOndergrens.check(opdracht, rekenTijd);
    }
}
